def get_flower_info(flower_name: str) -> dict:
    key = flower_name.lower().strip()

    # 1. Exact key match (fast path)
    if key in FLOWER_DATABASE:
        return FLOWER_DATABASE[key]

    # 2. Exact match against the entry's own common_name field.
    #    This is the most reliable match: e.g. searching "tulip" should
    #    hit the entry whose common_name IS "Tulip" (the "common tulip"
    #    dict key), not "siam tulip" which merely contains "tulip" as
    #    a substring.
    for db_key, info in FLOWER_DATABASE.items():
        if info.get("common_name", "").lower().strip() == key:
            return info

    # 3. Fuzzy substring fallback, picking the closest length match
    #    among all candidates instead of the first one encountered.
    candidates = []
    for db_key, info in FLOWER_DATABASE.items():
        if db_key in key or key in db_key:
            length_diff = abs(len(db_key) - len(key))
            candidates.append((length_diff, db_key, info))

    if candidates:
        candidates.sort(key=lambda c: c[0])
        return candidates[0][2]

    return {
        **DEFAULT_FLOWER_INFO,
        "common_name": flower_name.title(),
        "scientific_name": f"{flower_name.title()} sp."
    }

